svg.script:
const BASE = 'https://statevector-693279698669.us-central1.run.app';
const HASH = '3f0de3004fae209973c6ffea11d2da247b9799ad85a474b27f7307a642efb5f9';

const cell      = document.getElementById('cell');
const cellLabel  = document.getElementById('cellLabel');
const stateDisp  = document.getElementById('stateDisplay');
const tsDisp     = document.getElementById('tsDisplay');
const pollDisp   = document.getElementById('pollDisplay');
const pollDot    = document.getElementById('pollDot');
const hint       = document.getElementById('hint');

let lastTs = 0;

function render(s) {
  cell.setAttribute('fill', s.color);
  cell.setAttribute('r', s.radius);
  cellLabel.textContent = s.message;
  stateDisp.textContent = JSON.stringify(s);
}

async function poll() {
  try {
    // Flash the poll indicator
    pollDot.setAttribute('fill', '#3fb950');
    setTimeout(function(){ pollDot.setAttribute('fill', '#58a6ff'); }, 300);

    const r = await fetch(BASE + '/v/' + HASH);
    pollDisp.textContent = new Date().toLocaleTimeString();

    if (r.ok) {
      const d = await r.json();
      render(d.val);
      tsDisp.textContent = new Date(d.ts * 1000).toLocaleTimeString();

      // Flash on change
      if (d.ts !== lastTs) {
        hint.textContent = 'state changed!';
        hint.setAttribute('fill', '#3fb950');
        setTimeout(function(){
          hint.textContent = 'polling every 2s';
          hint.setAttribute('fill', '#484f58');
        }, 1500);
        lastTs = d.ts;
      }
    } else {
      stateDisp.textContent = 'no state found';
    }
  } catch(e) {
    stateDisp.textContent = 'error: ' + e.message;
  }
}

// Click feedback — you can see but not touch
cell.addEventListener('click', function() {
  hint.textContent = 'READ ONLY — no secret, no write';
  hint.setAttribute('fill', '#f85149');
  setTimeout(function(){
    hint.textContent = 'polling every 2s';
    hint.setAttribute('fill', '#484f58');
  }, 2000);
});

// Poll immediately, then every 2s
poll();
setInterval(poll, 2000);
